CREATE TABLE faqs (
    id         BIGSERIAL PRIMARY KEY,
    category   VARCHAR(60)   NOT NULL,
    question   VARCHAR(500)  NOT NULL,
    answer     VARCHAR(4000) NOT NULL,
    sort_order INT           NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ   NOT NULL,
    updated_at TIMESTAMPTZ   NOT NULL
);

INSERT INTO faqs (category, question, answer, sort_order, created_at, updated_at) VALUES
-- 시작하기
('시작하기', 'PostFlow는 어떤 서비스인가요?', 'Threads 콘텐츠를 AI로 만들고, 예약·자동 발행하고, 댓글을 자동 응답하고, 글이 만든 실제 매출(ROI)까지 추적하는 크리에이터용 자동화 워크스페이스입니다. "한 번 만들고 자동으로 성장"이 목표예요.', 10, now(), now()),
('시작하기', '회원가입은 어떻게 하나요?', '별도의 가입 절차가 없습니다. 로그인 화면에서 Google 계정으로 로그인하면 처음 로그인 시 자동으로 계정이 만들어지고, 다음부터는 같은 계정으로 로그인됩니다. 비밀번호를 따로 만들 필요가 없어요.', 11, now(), now()),
('시작하기', '무엇부터 시작하면 되나요?', '1) 설정 → Threads 연결에서 계정을 연결하고, 2) AI 생성에서 첫 콘텐츠를 만들고, 3) 저장 후 즉시 발행하거나 예약하세요. 대시보드 상단의 "시작하기" 체크리스트가 이 과정을 단계별로 안내합니다.', 12, now(), now()),
('시작하기', '대시보드의 "시작하기" 체크리스트는 무엇인가요?', 'Threads 연결 / 첫 콘텐츠 만들기 / 첫 발행·예약 3단계의 진행 상황을 보여주는 온보딩 카드입니다. 세 단계를 모두 마치면 자동으로 사라집니다.', 13, now(), now()),
('시작하기', '키보드로 빠르게 이동할 수 있나요?', '맥은 Cmd+K, 윈도우는 Ctrl+K를 누르면 커맨드 팔레트가 열립니다. 화면 이름을 입력해 어디로든 바로 이동하거나 빠른 작업을 실행할 수 있어요. 상단 바의 "검색·이동" 버튼으로도 열립니다.', 14, now(), now()),
-- AI 콘텐츠 생성
('AI 콘텐츠 생성', '콘텐츠는 어떻게 생성하나요?', 'AI 생성 화면에서 주제를 입력하고 목표·톤·개수를 고른 뒤 "생성"을 누르면 카드 형태로 여러 버전이 나옵니다. 마음에 드는 카드를 저장하면 라이브러리에 들어갑니다.', 20, now(), now()),
('AI 콘텐츠 생성', '목표와 톤은 무엇을 바꾸나요?', '목표(참여 유도·정보 전달·전환 등)와 톤(친근함·전문적 등)에 따라 AI가 글의 구조와 말투, 후킹 방식을 다르게 작성합니다. 같은 주제라도 결과가 달라져요.', 21, now(), now()),
('AI 콘텐츠 생성', '관심도 점수(0~100)는 무엇인가요?', '글이 사람들의 관심을 끌 가능성을 예측한 점수입니다. 첫 문장(훅)·길이·질문·CTA·해시태그·구조를 종합해 계산하며, 80 이상은 초록, 60~79는 주황, 60 미만은 빨강으로 표시됩니다. 빨강이면 개선을 권장해요. 이 점수는 키 없이도 계산됩니다.', 22, now(), now()),
('AI 콘텐츠 생성', '"훅 비교"는 무엇인가요?', '같은 주제로 첫 문장(훅)을 여러 개 만들어 점수와 함께 비교해주는 기능입니다. 가장 강한 도입부를 골라 글의 클릭률을 높일 수 있어요.', 23, now(), now()),
('AI 콘텐츠 생성', '생성된 글을 저장하면 어디로 가나요?', '저장하면 라이브러리에 초안 상태로 들어갑니다. 거기서 편집·예약·즉시 발행·복제할 수 있어요. 해시태그와 CTA도 함께 저장됩니다.', 24, now(), now()),
('AI 콘텐츠 생성', 'AI 생성이 안 돼요(오류가 떠요).', '대부분 AI 키 미설정 또는 크레딧 부족입니다. 화면에 백엔드의 안내 메시지가 그대로 표시되니 확인하세요. 관심도 점수·훅 점수 같은 분석 기능은 키 없이도 동작합니다.', 25, now(), now()),
('AI 콘텐츠 생성', '월 생성 횟수에 제한이 있나요?', '플랜별로 다릅니다. Free는 월 30회, Starter는 월 300회, Pro·Business는 무제한입니다. 한도에 도달하면 안내와 함께 업그레이드 버튼이 표시됩니다. 사용량은 계정 화면에서 확인할 수 있어요(매월 KST 기준 초기화).', 26, now(), now()),
-- 시리즈
('시리즈 생성', '시리즈 생성은 무엇인가요?', '하나의 주제로 7·14·30일짜리 연재 콘텐츠 플랜을 한 번에 만들어주는 기능입니다. 날짜별로 이어지는 글을 받아 꾸준한 발행에 활용하세요.', 30, now(), now()),
('시리즈 생성', '시리즈는 어떤 플랜부터 쓰나요?', 'Pro 플랜부터 사용할 수 있습니다. 하위 플랜에서 시도하면 안내와 함께 업그레이드 버튼이 표시됩니다.', 31, now(), now()),
-- 라이브러리
('라이브러리', '라이브러리는 무엇인가요?', '생성·저장한 모든 콘텐츠를 관리하는 곳입니다. 상태(초안·예약·발행), 관심도 점수, 예약/발행 시각을 한눈에 보고 검색·정렬·필터·일괄 작업을 할 수 있어요.', 40, now(), now()),
('라이브러리', '글을 검색하거나 복제할 수 있나요?', '상단 검색창에서 본문·해시태그·CTA로 검색할 수 있고, 각 행의 복제 버튼으로 같은 내용의 새 초안을 만들 수 있습니다(템플릿처럼 재사용).', 41, now(), now()),
('라이브러리', '여러 글을 한꺼번에 처리할 수 있나요?', '체크박스로 여러 글을 선택해 일괄 삭제 등 작업을 할 수 있습니다. 상단 체크박스로 전체 선택도 됩니다.', 42, now(), now()),
('라이브러리', '글을 클릭하면 무엇을 할 수 있나요?', '상세 모달이 열려 본문 편집, Threads 미리보기, 관심도 분석·개선 팁, 이미지 첨부, (다중계정 시) 발행 계정 선택을 할 수 있습니다.', 43, now(), now()),
-- 예약·스케줄
('예약·스케줄', '예약 발행은 어떻게 하나요?', '글 작성·상세 모달에서 발행 시각을 지정해 저장하면 예약됩니다. 스케줄 화면의 캘린더/목록에서 예약 현황을 볼 수 있고, 지정 시각에 자동 발행됩니다(Threads 연결 필요).', 50, now(), now()),
('예약·스케줄', '추천 발행 시간대는 무엇인가요?', '스케줄 화면 상단의 "추천 발행 시간대"는 반응이 좋은 일반적 패턴(평일 저녁·점심 등)을 점수로 제안합니다. 그 시간대에 맞춰 예약하면 노출에 유리해요.', 51, now(), now()),
('예약·스케줄', '예약 발행은 어떤 플랜부터 쓰나요?', 'Starter 플랜부터 사용할 수 있습니다. Free에서 예약을 시도하면 안내와 함께 업그레이드 버튼이 표시됩니다.', 52, now(), now()),
-- Threads 연결
('Threads 연결', 'Threads 계정은 어떻게 연결하나요?', '설정 → Threads 연결에서 "Threads 연결하기"를 누르면 팝업으로 Meta(OAuth) 인증이 진행됩니다. 인증을 마치면 연결되고, 예약·자동 발행을 쓸 수 있어요. 연결에는 서버 측 Threads 앱 키 설정이 필요합니다.', 60, now(), now()),
('Threads 연결', '다른 Threads 계정으로 바꾸려면 어떻게 하나요?', '연결된 계정 카드에서 "연결 해제" 후 다시 "연결하기"로 새 계정을 인증하면 됩니다. 단일 계정 플랜에서는 다른 계정으로 인증하면 현재 연결이 새 계정으로 교체됩니다. 단, 브라우저의 Threads 로그인 세션이 바꾸려는 계정이어야 합니다.', 61, now(), now()),
('Threads 연결', '연결하면 어떤 계정 정보가 보이나요?', '프로필 사진, 이름, @핸들, 소개, 그리고 팔로워 수와 최근 30일 조회·좋아요·답글·리포스트·인용 통계가 표시됩니다. (팔로잉 수는 Threads API가 제공하지 않습니다.)', 62, now(), now()),
('Threads 연결', '토큰이 만료되면 어떻게 되나요?', 'Threads 토큰은 60일짜리이며, 만료 전 자동으로 갱신됩니다. 갱신에 실패하면 "재연결 필요" 상태가 되고 알림으로 안내하니 다시 연결해주세요.', 63, now(), now()),
('Threads 연결', '여러 개의 Threads 계정을 연결할 수 있나요?', '다중 계정은 Business 플랜부터 가능합니다. 그 외 플랜은 1개 계정만 사용하며, 새 계정을 연결하면 기존 계정이 교체됩니다.', 64, now(), now()),
('Threads 연결', '게시물마다 다른 계정으로 발행할 수 있나요?', '다중 계정을 연결한 경우, 상세 모달에서 그 게시물의 발행 계정을 선택할 수 있습니다. 지정하지 않으면 기본 계정으로 발행됩니다.', 65, now(), now()),
-- 댓글 자동화
('댓글 자동화', '댓글 자동화는 무엇인가요?', '게시물 댓글에 특정 키워드가 달리면 자동으로 답글을 보내는 기능입니다. 키워드·대상 게시물·답글 템플릿으로 규칙을 만들면 스케줄러가 주기적으로 확인해 응답합니다.', 70, now(), now()),
('댓글 자동화', '답글에 링크를 자동으로 넣을 수 있나요?', '답글 템플릿에 {link}를 넣고 규칙에 추적 링크를 연결하면, 자동 응답 시 {link}가 그 추적 단축 URL로 치환됩니다. 댓글로 자연스럽게 전환을 유도할 수 있어요.', 71, now(), now()),
('댓글 자동화', '규칙이 잘 동작하는지 미리 볼 수 있나요?', '규칙 목록의 "테스트"에서 예시 댓글을 넣어 규칙이 매칭되는지, 어떤 답글이 나갈지 미리 확인할 수 있습니다.', 72, now(), now()),
-- 추적링크·ROI·전환 웹훅
('추적링크·ROI', '추적 링크(짧은 URL)는 무엇인가요?', '글에서 외부 링크로 보내는 클릭을 측정하기 위한 단축 URL입니다. 분석 → ROI에서 게시물에 추적 링크를 만들면 /r/코드 형태의 주소가 생기고, 클릭 수가 집계됩니다. 봇·중복 클릭은 제외됩니다.', 80, now(), now()),
('추적링크·ROI', '리드 캡처는 무엇인가요?', '추적 링크 생성 시 리드 캡처를 켜면, 링크 클릭 시 이메일을 받는 폼을 거쳐 목적지로 이동합니다. 수집된 이메일(리드)은 ROI 지표에 반영됩니다.', 81, now(), now()),
('추적링크·ROI', 'ROI(수익률)는 어떻게 계산되나요?', '게시물별 매출(전환)에서 비용을 뺀 순수익을 비용으로 나눠 백분율로 보여줍니다. 매출은 전환 웹훅으로, 비용은 직접 입력해 반영합니다. 분석 → 수익(ROI) 탭에서 총매출·ROI%·게시물별 매출을 확인하세요.', 82, now(), now()),
('추적링크·ROI', '전환 웹훅이란 무엇인가요?', '내 쇼핑몰·강의·예약 등 외부에서 결제(전환)가 일어났을 때, 그 매출을 PostFlow의 해당 글에 자동으로 연결해주는 수신용 알림 채널입니다. 외부 시스템이 결제 완료 시 정해진 형식으로 요청을 보내면 ROI에 집계됩니다.', 83, now(), now()),
('추적링크·ROI', '전환 웹훅은 어떻게 연동하나요?', '계정 화면의 전환 웹훅 카드에서 시크릿을 발급받고 "연동 가이드"를 펼치면 복사해 쓸 수 있는 예제 코드가 있습니다. 본문(slug 또는 postId, amount 등)을 HMAC-SHA256(타임스탬프.본문)으로 서명해 헤더와 함께 POST하면 됩니다. 비개발자는 개발자에게 이 가이드를 전달하세요.', 84, now(), now()),
('추적링크·ROI', '게시물 비용은 어떻게 넣나요?', '분석 → ROI에서 게시물별로 제작·광고 비용을 입력하면 순수익과 ROI% 계산에 반영됩니다.', 85, now(), now()),
-- 플랜·결제·구독
('플랜·결제', '플랜은 어떤 차이가 있나요?', 'Free(월 30회 생성), Starter(월 300회+예약), Pro(무제한+시리즈+분석), Business(다중 계정+우선 지원)로 나뉩니다. 계정 화면에서 현재 플랜과 사용량, 기능 잠금 상태를 볼 수 있어요.', 90, now(), now()),
('플랜·결제', '업그레이드는 어떻게 하나요?', '계정 화면의 플랜 카드 또는 좌측 하단/한도 안내의 "업그레이드" 버튼으로 진행합니다. 결제가 설정된 환경에서는 결제 페이지로 이동하고, 완료되면 즉시 플랜이 적용됩니다.', 91, now(), now()),
('플랜·결제', '결제 수단은 무엇인가요?', '카드 결제(Stripe)를 사용합니다. 국내외 카드를 지원하며, 구독(정기결제) 방식입니다.', 92, now(), now()),
('플랜·결제', '구독을 취소하면 바로 끊기나요?', '아니요. 결제한 기간은 끝까지 그대로 이용할 수 있고, 기간이 끝나는 시점에 자동으로 무료 플랜으로 전환됩니다. 계정 화면에 "○○일까지 이용 가능" 안내가 표시됩니다.', 93, now(), now()),
('플랜·결제', '구독은 어디서 취소·관리하나요?', '계정 화면의 플랜 영역에서 "구독 취소·관리"로 진행합니다. 결제 환경에서는 결제사 관리 페이지로 이동해 취소·카드 변경·영수증 확인을 할 수 있어요.', 94, now(), now()),
-- 기타
('기타', '알림은 무엇을 알려주나요?', '상단 종 아이콘에서 발행 실패, Threads 재연결 필요, 토큰 만료 임박 등 조치가 필요한 항목을 알려줍니다. 클릭하면 해당 화면으로 이동합니다.', 100, now(), now()),
('기타', '데이터를 백업할 수 있나요?', '계정 화면의 "데이터 내보내기"에서 내 게시물 전체를 CSV 또는 JSON 파일로 내려받을 수 있습니다.', 101, now(), now()),
('기타', '다크 모드를 쓸 수 있나요?', '계정 화면 또는 상단의 테마 토글에서 라이트·다크·시스템 모드를 선택할 수 있습니다. 시스템 모드는 기기 설정을 따릅니다.', 102, now(), now()),
('기타', '로그아웃은 어디서 하나요?', '상단 우측 또는 계정 화면에서 로그아웃할 수 있습니다. 다시 들어올 때 같은 Google 계정으로 로그인하면 기존 데이터가 그대로 있습니다.', 103, now(), now()),
('기타', '문의는 어디로 하나요?', '서비스 관련 문의는 deerkrg@gmail.com 으로 보내주세요. 약관·개인정보 처리방침은 로그인·계정 화면 하단 링크에서 확인할 수 있습니다.', 104, now(), now());
